(()=>{(function(){"use strict";const a={beran:{name:"Beran",emoji:"\u2648",element:"Ohe\u0148",barva:"#e74c3c",focus:"svou odvahu a p\u0159irozenou ak\u010Dnost",vizObraz:"jasn\xFD plamen ve tv\xE9m srdci \u2014 \u010Dist\xFD, pevn\xFD a nekontrolovateln\xFD",mantraSlovo:"odvaze",ruler:"Mars",uzemeniVeta:"C\xEDt\xED\u0161 Martovu energii \u2014 p\u0159ipravenou k akci, ne k \u010Dek\xE1n\xED.",uzavreniVeta:"Mars stoj\xED za tebou. Jde\u0161 vp\u0159ed.",journalQ:"Kde byla dnes moje reakce okam\u017Eit\xE1 a spr\xE1vn\xE1 \u2014 bez p\u0159\xEDli\u0161n\xE9ho p\u0159em\xFD\u0161len\xED?"},byk:{name:"Byk",emoji:"\u2649",element:"Zem\u011B",barva:"#27ae60",focus:"svou stabilitu a propojen\xED s p\u0159\xEDrodou",vizObraz:"hlubok\xE9 ko\u0159eny stromu, kter\xE9 dr\u017E\xED pevn\u011B v zemi bez ohledu na v\xEDtr",mantraSlovo:"stabilit\u011B",ruler:"Venu\u0161e",uzemeniVeta:"C\xEDt\xED\u0161 pevnou zemi pod nohama \u2014 tv\u016Fj p\u0159irozen\xFD zdroj s\xEDly.",uzavreniVeta:"Venu\u0161e t\u011B prov\xE1z\xED ka\u017Ed\xFDm klidn\xFDm krokem kup\u0159edu.",journalQ:"Co mi dnes p\u0159ineslo skute\u010Dn\xFD pocit bezpe\u010D\xED a vnit\u0159n\xEDho klidu?"},blizenci:{name:"Bl\xED\u017Eenci",emoji:"\u264A",element:"Vzduch",barva:"#f39c12",focus:"svou zv\xEDdavost a schopnost spojovat protiklady",vizObraz:"\u010Dist\xFD horsk\xFD vzduch, kter\xFD pro\u010Di\u0161\u0165uje ka\u017Edou my\u0161lenku",mantraSlovo:"jasnosti",ruler:"Merkur",uzemeniVeta:"Tv\u016Fj merkurovsk\xFD um se \u010Dist\xED jako vzduch po de\u0161ti \u2014 pohybliv\xFD a jasn\xFD.",uzavreniVeta:"Merkur nese tvoje z\xE1m\u011Bry p\u0159esn\u011B tam, kam maj\xED j\xEDt.",journalQ:"Jak\xE1 neo\u010Dek\xE1van\xE1 spojitost se mi dnes uk\xE1zala \u2014 a co by mohla znamenat?"},rak:{name:"Rak",emoji:"\u264B",element:"Voda",barva:"#2980b9",focus:"svou intuici a schopnost pe\u010Dovat o druh\xE9 i o sebe",vizObraz:"klidn\xE1 hladina jezera, kter\xE1 zrcadl\xED hv\u011Bzdy dokonale",mantraSlovo:"intuici",ruler:"M\u011Bs\xEDc",uzemeniVeta:"Jsi v domovin\u011B M\u011Bs\xEDce \u2014 \u017E\xE1dn\xE9 jin\xE9 znamen\xED nec\xEDt\xED lun\xE1rn\xED energii tak p\u0159irozen\u011B jako ty.",uzavreniVeta:"Tv\u016Fj M\u011Bs\xEDc ti otev\u0159el p\u0159esn\u011B to, co pot\u0159ebuje\u0161 vid\u011Bt.",journalQ:"Co mi dnes \u0159ekla moje intuice jako prvn\xED \u2014 a jak\xE1 byla moje reakce?"},lev:{name:"Lev",emoji:"\u264C",element:"Ohe\u0148",barva:"#e67e22",focus:"svou tvo\u0159ivost a p\u0159irozen\xE9 sebevyj\xE1d\u0159en\xED",vizObraz:"zlat\xE9 slune\u010Dn\xED sv\u011Btlo vych\xE1zej\xEDc\xED p\u0159\xEDmo z tv\xE9ho srdce",mantraSlovo:"tvo\u0159ivosti",ruler:"Slunce",uzemeniVeta:"Slune\u010Dn\xED z\xE1\u0159e ve tv\xE9m srdci sv\xEDt\xED i v noci \u2014 to je tv\u016Fj p\u0159irozen\xFD stav.",uzavreniVeta:"Slune\u010Dn\xED energie z\u016Fst\xE1v\xE1 v tob\u011B \u2014 je\u0161t\u011B dlouho po zhasnut\xE9 sv\xED\u010Dce.",journalQ:"Kde dnes moje sv\u011Btlo p\u0159irozen\u011B zaz\xE1\u0159ilo \u2014 a jak to ovlivnilo lidi kolem m\u011B?"},panna:{name:"Panna",emoji:"\u264D",element:"Zem\u011B",barva:"#8e44ad",focus:"svou preciznost a schopnost vid\u011Bt kr\xE1su v detailech",vizObraz:"\u010Dist\xE1 pr\u016Fzra\u010Dn\xE1 voda tekouc\xED p\u0159es hladk\xE9 kameny",mantraSlovo:"p\xE9\u010Di",ruler:"Merkur",uzemeniVeta:"Tvoje p\u0159irozen\xE1 preciznost je dar \u2014 nech ji pracovat ti\u0161e a p\u0159esn\u011B pro tebe.",uzavreniVeta:"Ka\u017Ed\xFD detail, jemu\u017E v\u011Bnuje\u0161 p\xE9\u010Di, roste a p\u0159in\xE1\u0161\xED ovoce.",journalQ:"Jak\xFD detail dnes zachytila moje pozornost, zat\xEDmco ostatn\xED ho p\u0159ehl\xE9dli \u2014 a co to odhalilo?"},vahy:{name:"V\xE1hy",emoji:"\u264E",element:"Vzduch",barva:"#16a085",focus:"svou touhu po harmonii ve vztaz\xEDch i v sob\u011B",vizObraz:"dokonale vyv\xE1\u017Een\xE9 zlat\xE9 v\xE1hy klidn\u011B spo\u010D\xEDvaj\xEDc\xED ve st\u0159edu",mantraSlovo:"harmonii",ruler:"Venu\u0161e",uzemeniVeta:"Tvoje vnit\u0159n\xED v\xE1hy se ti\u0161e vyrovn\xE1vaj\xED \u2014 Venu\u0161e t\u011B v tom podporuje.",uzavreniVeta:"Harmonie, po kter\xE9 tou\u017E\xED\u0161, v\u017Edy za\u010D\xEDn\xE1 uvnit\u0159 tebe.",journalQ:"Kde dnes vn\xE1\u0161\xEDm rovnov\xE1hu do vztah\u016F nebo situac\xED \u2014 v\u011Bdom\u011B, nebo instinktivn\u011B?"},stir:{name:"\u0160t\xEDr",emoji:"\u264F",element:"Voda",barva:"#c0392b",focus:"svou hloubku a schopnost proch\xE1zet transformac\xED",vizObraz:"f\xE9nix stoupaj\xEDc\xED z temn\xE9 vody \u2014 prom\u011Bn\u011Bn\xFD, siln\u011Bj\u0161\xED, svobodn\xFD",mantraSlovo:"transformaci",ruler:"Pluto",uzemeniVeta:"Temnota t\u011B nestra\u0161\xED \u2014 p\u0159irozen\u011B z n\xED \u010Derp\xE1\u0161 svou nejv\u011Bt\u0161\xED s\xEDlu.",uzavreniVeta:"Pluto stvrdil tvou prom\u011Bnu. Jsi siln\u011Bj\u0161\xED ne\u017E na za\u010D\xE1tku tohoto ritu\xE1lu.",journalQ:"Co z toho, co d\u0159\xEDv tvo\u0159ilo ned\xEDlnou sou\u010D\xE1st m\u011B, dnes dok\xE1\u017Eu pustit?"},strelec:{name:"St\u0159elec",emoji:"\u2650",element:"Ohe\u0148",barva:"#d35400",focus:"svou touhu po expanzi, pravd\u011B a svobod\u011B",vizObraz:"\u0161\xEDp let\xEDc\xED p\u0159esn\u011B a s jistotou k vzd\xE1len\xE9mu c\xEDli",mantraSlovo:"svobod\u011B",ruler:"Jupiter",uzemeniVeta:"Jupiter roz\u0161i\u0159uje tv\u016Fj obzor \u2014 c\xEDt\xED\u0161 tu prostorovost a svobodu?",uzavreniVeta:"Tv\u016Fj \u0161\xEDp let\xED. Svoboda je vnit\u0159n\xED stav \u2014 a ty ji nos\xED\u0161 st\xE1le v sob\u011B.",journalQ:"Kam p\u0159esn\u011B m\xED\u0159\xED m\u016Fj z\xE1m\u011Br \u2014 a je to st\xE1le pravda a svoboda, po n\xED\u017E skute\u010Dn\u011B tou\u017E\xEDm?"},kozoroh:{name:"Kozoroh",emoji:"\u2651",element:"Zem\u011B",barva:"#7f8c8d",focus:"svou discipl\xEDnu a vizi dlouhodob\xE9ho z\xE1m\u011Bru",vizObraz:"hora, kter\xE1 stoj\xED pevn\u011B tis\xEDce let \u2014 neochv\u011Bjn\xE1 a majest\xE1tn\xED",mantraSlovo:"vytrvalosti",ruler:"Saturn",uzemeniVeta:"Saturn ti d\xE1v\xE1 dar trp\u011Blivosti \u2014 nejcenn\u011Bj\u0161\xED ze v\u0161ech zdroj\u016F.",uzavreniVeta:"K\xE1men po kameni, krok po kroku \u2014 tak se stav\xED hory i cel\xE9 \u017Eivoty.",journalQ:"Jak\xFD dlouhodob\xFD z\xE1m\u011Br se dnes d\xEDky mn\u011B posunul o jeden konkr\xE9tn\xED, m\u011B\u0159iteln\xFD krok vp\u0159ed?"},vodnar:{name:"Vodn\xE1\u0159",emoji:"\u2652",element:"Vzduch",barva:"#2471a3",focus:"svou originalitu a vizi lep\u0161\xEDho sv\u011Bta",vizObraz:"hv\u011Bzdy propojen\xE9 sv\u011Bteln\xFDmi vl\xE1kny do jednoho velk\xE9ho vzoru",mantraSlovo:"vizi",ruler:"Uran",uzemeniVeta:"Tvoje vize p\u0159edb\xEDh\xE1 dobu \u2014 Uran t\u011B pos\xEDl\xE1 tam, kde ostatn\xED je\u0161t\u011B nejsou.",uzavreniVeta:"Uran p\u0159in\xE1\u0161\xED revoluci. Ty ji vede\u0161 \u2014 klidn\u011B, v\u011Bdom\u011B, s p\u0159ehledem.",journalQ:"Jak\xE1 neobvykl\xE1 my\u0161lenka m\u011B dnes napadla \u2014 a co by se stalo, kdyby dostala pln\xFD prostor?"},ryby:{name:"Ryby",emoji:"\u2653",element:"Voda",barva:"#1a5276",focus:"sv\u016Fj soucit a intuici p\u0159esahuj\xEDc\xED rozum",vizObraz:"tich\xE9 hlubok\xE9 mo\u0159e, jeho\u017E dno skr\xFDv\xE1 starod\xE1vnou moudrost",mantraSlovo:"soucitu",ruler:"Neptun",uzemeniVeta:"Neptunova hlubina v tob\u011B je bezpe\u010Dn\xE1 \u2014 nech ji proz\xE1\u0159it tvoje tu\u0161en\xED.",uzavreniVeta:"Tvoje intuice je most mezi sv\u011Bty. D\u016Fv\u011B\u0159uj j\xED \u2014 vede t\u011B p\u0159esn\u011Bji ne\u017E jak\xE1koliv logika.",journalQ:"Jak\xFD sen, pocit nebo tu\u0161en\xED dnes dostaly mou pozornost \u2014 a co mi tich\xFDm hlasem \u0159\xEDkaly?"}},n={"new-moon":{nazevPrefix:"Ritu\xE1l z\xE1m\u011Br\u016F",tema:"Nov\xFD za\u010D\xE1tek \u2014 set\xED z\xE1m\u011Br\u016F do temnoty",popis:e=>`Novolun\xED je kosmick\xFDm resetem. Pr\xE1zdn\xFD M\u011Bs\xEDc p\u0159ij\xEDm\xE1 z\xE1m\u011Bry jako \xFArodn\xE1 p\u016Fda sem\xEDnka. ${e.element} t\u011B dnes podporuje ve formulov\xE1n\xED toho, co skute\u010Dn\u011B chce\u0161 p\u0159iv\xE9st do sv\xE9ho \u017Eivota.`,prepList:["Sv\xED\u010Dka (b\xEDl\xE1 nebo st\u0159\xEDbrn\xE1)","Pap\xEDr a tu\u017Eka","Klidn\xE9 m\xEDsto na 10 minut","Sklenka vody"],duration:"8\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsvi\u0165 sv\xED\u010Dku a sedni si pohodln\u011B. T\u0159ikr\xE1t zhluboka d\xFDchej \u2014 n\xE1dech nosem na 4 doby, zadr\u017E na 4, v\xFDdech \xFAsty na 6. S ka\u017Ed\xFDm v\xFDdechem pus\u0165 nap\u011Bt\xED tohoto dne. Nech ticho novolun\u011Bn\xED, aby t\u011B zahalilo jako p\u0159ikr\xFDvka. ${e.uzemeniVeta}`,subtext:"P\u0159\xEDprava posv\xE1tn\xE9ho prostoru"},{title:"Z\xE1m\u011Br",text:e=>`Polo\u017E ruku na srdce. V tichu se zeptej: "Co chci p\u0159iv\xE9st do sv\xE9ho \u017Eivota v p\u0159\xED\u0161t\xEDch 29 dnech?" Nech ${e.focus} mluvit jako prvn\xED \u2014 bez cenzury, bez posuzov\xE1n\xED. Naslouchej.`,subtext:"\u010Cas vnit\u0159n\xEDho naslouch\xE1n\xED"},{title:"Vizualizace",text:e=>`Zav\u0159i o\u010Di. P\u0159edstav si ${e.vizObraz}. Pak si p\u0159edstav, jak tento obraz stoup\xE1 k temn\xE9mu M\u011Bs\xEDci na obloze. M\u011Bs\xEDc p\u0159ij\xEDm\xE1 tv\u016Fj z\xE1m\u011Br jako sem\xEDnko do posv\xE1tn\xE9 p\u016Fdy. Vydr\u017E u tohoto obrazu 2 minuty.`,subtext:"Set\xED z\xE1m\u011Br\u016F do lun\xE1rn\xEDho pole"},{title:"Fyzick\xFD \xFAkon",text:e=>'Vezmi pap\xEDr a napi\u0161 3 z\xE1m\u011Bry v p\u0159\xEDtomn\xE9m \u010Dase \u2014 jako by se u\u017E d\u011Bly. Za\u010Dni slovy "Jsem\u2026", "M\xE1m\u2026", nebo "P\u0159ij\xEDm\xE1m\u2026". Pap\xEDr p\u0159elo\u017E a uschovej na bezpe\u010Dn\xE9m m\xEDst\u011B a\u017E do \xDApl\u0148ku \u2014 a sleduj, jak se z\xE1m\u011Bry napl\u0148uj\xED.',subtext:"Z\xE1m\u011Bry zapsan\xE9 se st\xE1vaj\xED realitou"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakuj nahlas nebo v duchu:

\u201EV ${e.mantraSlovo} a tichu novolun\xED zas\xEDv\xE1m svou budoucnost.
Nech\u0165 p\u0159ijde v prav\xFD \u010Das \u2014 pod veden\xEDm ${e.ruler}."`,subtext:"Opakuj t\u0159ikr\xE1t \u2014 s pln\xFDm p\u0159esv\u011Bd\u010Den\xEDm"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkuj M\u011Bs\xEDci za jeho skrytou s\xEDlu temnoty. Pod\u011Bkuj sob\u011B za \u010Das v\u011Bnovan\xFD t\xE9to praxi. ${e.uzavreniVeta} Zhasni sv\xED\u010Dku v\u011Bdom\u011B, jako akt uzav\u0159en\xED posv\xE1tn\xE9ho prostoru. Tv\u016Fj z\xE1m\u011Br byl p\u0159ijat.`,subtext:"Ritu\xE1l je dokon\u010Den"}],journalPrompts:e=>["Co se ve mn\u011B pohnulo p\u0159i formulov\xE1n\xED z\xE1m\u011Br\u016F? Co m\u011B p\u0159ekvapilo?","Jak\xE9 \u010D\xE1sti z\xE1m\u011Bru mi jde nejh\u016F\u0159 uv\u011B\u0159it \u2014 a co to \u0159\xEDk\xE1 o m\xE9 v\xED\u0159e v sebe?","Co mus\xEDm pustit, aby nov\xFD za\u010D\xE1tek mohl p\u0159ij\xEDt?",e.journalQ]},"waxing-crescent":{nazevPrefix:"Ritu\xE1l prvn\xEDho kroku",tema:"Dor\u016Fstaj\xEDc\xED srpek \u2014 odvaha k prvn\xED akci",popis:e=>`Tenk\xFD srpek M\u011Bs\xEDce se zjevuje jako prvn\xED p\u0159\xEDslib. Je \u010Das jednat na z\xE1klad\u011B z\xE1m\u011Br\u016F. Tv\u016Fj \u017Eivel \u2014 ${e.element.toLowerCase()} \u2014 t\u011B poh\xE1n\xED: mal\xFD, ale re\xE1ln\xFD krok dnes m\u016F\u017Ee zm\u011Bnit v\u0161e.`,prepList:["Sv\xED\u010Dka","Pap\xEDr a tu\u017Eka","Pohodln\xE9 m\xEDsto k sezen\xED"],duration:"7\u20139 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsvi\u0165 sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchej. S ka\u017Ed\xFDm v\xFDdechem propus\u0165 jeden strach nebo pochybnost. Nech dor\u016Fstaj\xEDc\xED energii M\u011Bs\xEDce proudit tv\xFDm t\u011Blem jako prvn\xED rann\xED sv\u011Btlo. ${e.uzemeniVeta}`,subtext:"P\u0159\xEDprava na akci"},{title:"Z\xE1m\u011Br",text:e=>`Polo\u017E ruku na hrudn\xEDk. Vzpome\u0148 si na z\xE1m\u011Bry ze za\u010D\xE1tku cyklu. Zeptej se: "Jak\xFD JEDEN konkr\xE9tn\xED krok m\u016F\u017Eu ud\u011Blat je\u0161t\u011B dnes?" Nech ${e.focus}, a\u0165 ti uk\xE1\u017Ee cestu. V\u011B\u0159 prvn\xED my\u0161lence, kter\xE1 p\u0159ijde.`,subtext:"Propojen\xED se z\xE1m\u011Brem"},{title:"Vizualizace",text:e=>`Zav\u0159i o\u010Di. P\u0159edstav si ${e.vizObraz}. Tento obraz t\u011B vede jako lucerna v \u0161eru. Te\u010F si vizualizuj sebe, jak d\u011Bl\xE1\u0161 ten jeden krok \u2014 s lehkost\xED, s jistotou, bez v\xE1h\xE1n\xED. Ci\u0165 tu lehkost v cel\xE9m t\u011Ble.`,subtext:"Vizualizace odhodl\xE1n\xED"},{title:"Fyzick\xFD \xFAkon",text:e=>'Napi\u0161 na pap\xEDr: "Dnes ud\u011Bl\xE1m: ___________." Vypl\u0148 jednu konkr\xE9tn\xED, splnitelnou akci. Pak tento z\xE1vazek nech na viditeln\xE9m m\xEDst\u011B jako p\u0159ipom\xEDnku. A tu akci ud\u011Blej \u2014 je\u0161t\u011B dnes.',subtext:"Z\xE1vazek stvrzen\xFD p\xEDsmem"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakuj:

\u201EV ${e.mantraSlovo} kon\xE1m prvn\xED krok.
M\u011Bs\xEDc roste se mnou \u2014 a ${e.ruler} mi d\xE1v\xE1 s\xEDlu."`,subtext:"Opakuj t\u0159ikr\xE1t"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkuj si za odvahu za\u010D\xEDt. Ka\u017Ed\xE1 velk\xE1 cesta za\u010D\xEDn\xE1 krokem, kter\xFD vypad\xE1 mal\xFD. ${e.uzavreniVeta} Zhasni sv\xED\u010Dku v\u011Bdom\u011B. Tvoje odhodl\xE1n\xED bylo stvrzeno.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Co m\u011B v prvn\xEDm kroku nejv\xEDce brzd\xED? Je to re\xE1ln\xE1 p\u0159ek\xE1\u017Eka, nebo jen strach z nezn\xE1m\xE9ho?","Jak se budu c\xEDtit, a\u017E ten krok ud\u011Bl\xE1m \u2014 i kdyby se uk\xE1zalo, \u017Ee byl \u0161patn\xFD?","Komu m\u016F\u017Eu \u0159\xEDct o sv\xE9m z\xE1m\u011Bru, aby m\u011B ve spr\xE1vnou chv\xEDli podpo\u0159il?",e.journalQ]},"first-quarter":{nazevPrefix:"Ritu\xE1l rozhodnosti",tema:"Prvn\xED \u010Dtvr\u0165 \u2014 v\u016Fle skrze p\u0159ek\xE1\u017Eky",popis:e=>`P\u0159esn\u011B polovina M\u011Bs\xEDce je osv\u011Btlena \u2014 symbolick\xE9 nap\u011Bt\xED mezi z\xE1m\u011Brem a realitou. P\u0159ich\xE1z\xED prvn\xED odpor. Tv\u016Fj \u017Eivel \u2014 ${e.element.toLowerCase()} \u2014 ti d\xE1v\xE1 s\xEDlu p\u0159ek\xE1\u017Ekou proj\xEDt, ne se vr\xE1tit.`,prepList:["Sv\xED\u010Dka","Pap\xEDr a tu\u017Eka","Tich\xE9 m\xEDsto"],duration:"8\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsvi\u0165 sv\xED\u010Dku. Stoupni si pevn\u011B nohama na zem. T\u0159ikr\xE1t zhluboka d\xFDchej. Ci\u0165 stabilitu pod sebou. \u017D\xE1dn\xE1 p\u0159ek\xE1\u017Eka t\u011B nevyko\u0159en\xED \u2014 stoj\xED\u0161 pevn\u011B jako strom. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED ve v\u016Fli"},{title:"Z\xE1m\u011Br",text:e=>`Zav\u0159i o\u010Di a pojmenuj jednu p\u0159ek\xE1\u017Eku, kter\xE1 ti v tuto chv\xEDli stoj\xED v cest\u011B. Bu\u010F co nejp\u0159esn\u011Bj\u0161\xED \u2014 ne "nem\xE1m \u010Das", ale "konkr\xE9tn\u011B XY m\u011B blokuje, proto\u017Ee..." Nech ${e.focus} odhalit skute\u010Dnou p\u0159\xED\u010Dinu.`,subtext:"Pojmenov\xE1n\xED p\u0159ek\xE1\u017Eky"},{title:"Vizualizace",text:e=>`Zav\u0159i o\u010Di. P\u0159edstav si ${e.vizObraz}. Te\u010F si p\u0159edstav tu p\u0159ek\xE1\u017Eku jako ze\u010F p\u0159ed sebou. A pak si p\u0159edstav, jak ji p\u0159ekra\u010Duje\u0161 \u2014 krok za krokem. Soust\u0159e\u010F se ne na ze\u010F, ale na to, jak se c\xEDt\xED\u0161 na druh\xE9 stran\u011B.`,subtext:"Vizualizace pr\u016Fchodu"},{title:"Fyzick\xFD \xFAkon",text:e=>'Napi\u0161 p\u0159ek\xE1\u017Eku na pap\xEDr. Pod ni napi\u0161: "Moje \u0159e\u0161en\xED: ___________." Pap\xEDr p\u0159elo\u017E na p\u016Fl \u2014 symbolicky p\u0159ekon\xE1v\xE1\u0161 tu hranici. Uschovej ho, nebo vyho\u010F podle pocitu. P\u0159ek\xE1\u017Eka zapsan\xE1 je p\u0159ek\xE1\u017Eka nap\u016Fl vy\u0159e\u0161en\xE1.',subtext:"Symbolick\xE9 p\u0159ekon\xE1n\xED hranice"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakuj:

\u201EV ${e.mantraSlovo} a odhodl\xE1n\xED proch\xE1z\xEDm p\u0159ek\xE1\u017Ekou.
Nic m\u011B nezastavuje \u2014 ${e.ruler} stoj\xED za mnou."`,subtext:"Opakuj t\u0159ikr\xE1t s p\u0159esv\u011Bd\u010Den\xEDm"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkuj si za odvahu pojmenovat to, co t\u011B brzd\xED. P\u0159ek\xE1\u017Eka pojmenovan\xE1 je nap\u016Fl p\u0159ekonan\xE1. ${e.uzavreniVeta} Zhasni sv\xED\u010Dku. Jde\u0161 d\xE1l.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Co tato p\u0159ek\xE1\u017Eka \u0159\xEDk\xE1 o m\xFDch skute\u010Dn\xFDch hodnot\xE1ch a o tom, co opravdu chci?","Kdo nebo co mi v minulosti pomohlo p\u0159ekonat podobnou situaci?","Jak vypad\xE1 verze m\u011B, kter\xE1 stoj\xED na druh\xE9 stran\u011B t\xE9to v\xFDzvy?",e.journalQ]},"waxing-gibbous":{nazevPrefix:"Ritu\xE1l vylad\u011Bn\xED",tema:"Dor\u016Fstaj\xEDc\xED m\u011Bs\xEDc \u2014 zdokonalov\xE1n\xED a vytrvalost",popis:e=>`M\u011Bs\xEDc je t\xE9m\u011B\u0159 pln\xFD a energie kulminuje. Je \u010Das doladit, ne za\u010D\xEDnat znovu. Tv\u016Fj \u017Eivel \u2014 ${e.element.toLowerCase()} \u2014 ti pom\xE1h\xE1 vid\u011Bt, co funguje, a s p\xE9\u010D\xED to dov\xE9st k dokonalosti.`,prepList:["Sv\xED\u010Dka","Den\xEDk nebo pap\xEDr","Klidn\xE9 m\xEDsto"],duration:"7\u20139 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsvi\u0165 sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchej \u2014 s v\u011Bdomou vd\u011B\u010Dnost\xED za to, jak daleko od novolun\u011Bn\xED tvoje cesta do\u0161la. Ci\u0165 momentum tohoto cyklu: m\xE1\u0161 za sebou t\u0159i \u010Dtvrtiny cesty. ${e.uzemeniVeta}`,subtext:"Vd\u011B\u010Dn\xE9 uzem\u011Bn\xED"},{title:"Z\xE1m\u011Br",text:e=>`Vzpome\u0148 si na z\xE1m\u011Br tohoto cyklu. Zeptej se: "Co funguje v\xFDborn\u011B? A co pot\u0159ebuje malou, p\u0159esnou korekci?" Nech ${e.focus}, a\u0165 ti uk\xE1\u017Ee, kde je prostor pro zdokonalen\xED. Mal\xE9 vylad\u011Bn\xED m\u016F\u017Ee zm\u011Bnit v\u0161e.`,subtext:"Reflexe pokroku a korekce"},{title:"Vizualizace",text:e=>`Zav\u0159i o\u010Di. P\u0159edstav si ${e.vizObraz}. Te\u010F si p\u0159edstav sv\u016Fj z\xE1m\u011Br jako z 90 % dokon\u010Den\xE9 um\u011Bleck\xE9 d\xEDlo \u2014 jak\xFD detail chyb\xED? Co ho dokonale dokon\u010D\xED? Vizualizuj v\xFDsledek s precizn\xED, radostnou jasnost\xED.`,subtext:"Vizualizace dokon\u010Den\xED"},{title:"Fyzick\xFD \xFAkon",text:e=>'Napi\u0161 jednu konkr\xE9tn\xED v\u011Bc, kterou vylad\xED\u0161 nebo dokon\u010D\xED\u0161 p\u0159ed \xDApl\u0148kem. Bu\u010F co nejkonkr\xE9tn\u011Bj\u0161\xED: ne "zlep\u0161\xEDm p\u0159\xEDstup", ale "ud\u011Bl\xE1m XY konkr\xE9tn\u011B dnes do 18:00." P\u0159esnost je v t\xE9to f\xE1zi nejsiln\u011Bj\u0161\xED zbran\xED.',subtext:"Konkr\xE9tn\xED z\xE1vazek k dokon\u010Den\xED"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakuj:

\u201EV ${e.mantraSlovo} a p\u0159esnosti dosahuji sv\xE9ho c\xEDle.
Jsem t\xE9m\u011B\u0159 tam \u2014 ${e.ruler} mi ukazuje posledn\xED krok."`,subtext:"Opakuj t\u0159ikr\xE1t"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkuj si za vytrvalost \u2014 je za tebou cel\xFD cyklus pr\xE1ce. \xDApln\u011Bk p\u0159ich\xE1z\xED a tvoje p\u0159\xEDprava je hotov\xE1. ${e.uzavreniVeta} Zhasni sv\xED\u010Dku. Posledn\xED krok t\u011B \u010Dek\xE1.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Co m\u011B v tomto cyklu nejv\xEDce p\u0159ekvapilo \u2014 v dobr\xE9m i v n\xE1ro\u010Dn\xE9m?","Jak\xFD jeden detail, pokud ho vylad\xEDm, posune cel\xFD z\xE1m\u011Br na jinou \xFArove\u0148?","Jak se budu c\xEDtit p\u0159i \xDApl\u0148ku, a\u017E to bude hotov\xE9?",e.journalQ]},"full-moon":{nazevPrefix:"Ritu\xE1l uvoln\u011Bn\xED",tema:"\xDApln\u011Bk \u2014 vrchol energie, oslava a propu\u0161t\u011Bn\xED",popis:e=>`M\u011Bs\xEDc je pln\u011B osv\u011Btlen. Emoce jsou zes\xEDleny, intuice naost\u0159ena. To, co bylo zaseto, se projevuje. Je \u010Das slavit, vd\u011B\u010Dit \u2014 a v\u011Bdom\u011B propustit v\u0161e, co ti u\u017E neslou\u017E\xED. Tv\u016Fj \u017Eivel \u2014 ${e.element.toLowerCase()} \u2014 je dnes na vrcholu.`,prepList:["Sv\xED\u010Dka (zlat\xE1 nebo b\xEDl\xE1)","Pap\xEDr a tu\u017Eka","Sklenka vody","Bezpe\u010Dn\xE9 m\xEDsto (p\u0159\xEDpadn\u011B pro sp\xE1len\xED pap\xEDru)"],duration:"10\u201312 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsvi\u0165 sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchej. Ci\u0165 plnou energii \xDApl\u0148ku \u2014 jak pronik\xE1 do ka\u017Ed\xE9 bu\u0148ky tv\xE9ho t\u011Bla. Jsi na vrcholu lun\xE1rn\xEDho cyklu. V\u0161e, co bylo zaseto, je nyn\xED viditeln\xE9. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED v pln\xE9 energii"},{title:"Z\xE1m\u011Br",text:e=>`Vzpome\u0148 si na z\xE1m\u011Bry ze za\u010D\xE1tku cyklu. Co se naplnilo? Co p\u0159i\u0161lo ne\u010Dekan\u011B? P\u0159ijmi s vd\u011B\u010Dnost\xED oboje. Pak se zeptej: "Co mus\xEDm pustit, aby mohl p\u0159ij\xEDt nov\xFD za\u010D\xE1tek?" Nech ${e.focus}, a\u0165 ti odpov\xED bez cenzury.`,subtext:"Sklize\u0148 a v\u011Bdom\xE1 volba propu\u0161t\u011Bn\xED"},{title:"Vizualizace",text:e=>`Zav\u0159i o\u010Di. P\u0159edstav si st\u0159\xEDbrn\xE9 sv\u011Btlo \xDApl\u0148ku, jak pln\xED celou tvou m\xEDstnost a pak i tebe. Pak si p\u0159edstav ${e.vizObraz}. Nech toto sv\u011Btlo proj\xEDt ka\u017Edou bu\u0148kou \u2014 o\u010Distit, naplnit a osvobodit. D\xFDchej sv\u011Btlo dovnit\u0159.`,subtext:"Vizualizace o\u010Disty a napln\u011Bn\xED"},{title:"Fyzick\xFD \xFAkon",text:e=>"Napi\u0161 na pap\xEDr, co chce\u0161 propustit \u2014 zvyk, my\u0161lenku, vztah, strach, p\u0159esv\u011Bd\u010Den\xED o sob\u011B. Pak pap\xEDr p\u0159etrhni na dv\u011B \u010D\xE1sti. Pokud m\xE1\u0161 mo\u017Enost, spal ho bezpe\u010Dn\u011B. Nebo ho v\u011Bdom\u011B ho\u010F do ko\u0161e. Propou\u0161t\xED\u0161.",subtext:"Ritu\xE1ln\xED propu\u0161t\u011Bn\xED"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakuj:

\u201EV ${e.mantraSlovo} a vd\u011B\u010Dnosti propou\u0161t\xEDm star\xE9.
C\xEDt\xEDm volnost a p\u0159ipravenost \u2014 ${e.ruler} otev\xEDr\xE1 nov\xFD cyklus."`,subtext:"Opakuj t\u0159ikr\xE1t \u2014 s lehkost\xED a vd\u011B\u010Dnost\xED"},{title:"Uzav\u0159en\xED",text:e=>`Vezmi sklenku vody a podr\u017E ji chv\xEDli v dlan\xEDch. P\u0159edstav si, jak do n\xED proud\xED sv\u011Btlo \xDApl\u0148ku. Vypij ji jako symbol p\u0159ijet\xED nov\xE9 energie. ${e.uzavreniVeta} Pod\u011Bkuj M\u011Bs\xEDci. Zhasni sv\xED\u010Dku.`,subtext:"Ritu\xE1l dokon\u010Den \u2014 cyklus se uzav\xEDr\xE1"}],journalPrompts:e=>["Co konkr\xE9tn\xEDho se v tomto lun\xE1rn\xEDm cyklu naplnilo nebo projevilo \u2014 i ne\u010Dekan\u011B?","Co propou\u0161t\xEDm a jak se c\xEDt\xEDm po tomto rozhodnut\xED? Co to uvoln\u011Bn\xED p\u0159inese?","Jak\xFD je prvn\xED z\xE1m\u011Br pro nov\xFD cyklus, kter\xFD brzy za\u010Dne?",e.journalQ]},"waning-gibbous":{nazevPrefix:"Ritu\xE1l vd\u011B\u010Dnosti",tema:"Ub\xFDvaj\xEDc\xED m\u011Bs\xEDc \u2014 sd\xEDlen\xED moudrosti a reflexe",popis:e=>`M\u011Bs\xEDc ub\xFDv\xE1 a energie se obrac\xED dovnit\u0159. Je \u010Das integrovat to, co \xDApln\u011Bk p\u0159inesl, a sd\xEDlet moudrost. Tv\u016Fj \u017Eivel \u2014 ${e.element.toLowerCase()} \u2014 t\u011B zve k hlubok\xE9 reflexi a p\u0159ed\xE1v\xE1n\xED.`,prepList:["Sv\xED\u010Dka","Den\xEDk nebo pap\xEDr","Tich\xE9 m\xEDsto","\u010Caj nebo tepl\xFD n\xE1poj (voliteln\u011B)"],duration:"8\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsvi\u0165 sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchej s v\u011Bdom\xEDm, \u017Ee ub\xFDvaj\xEDc\xED sv\u011Btlo M\u011Bs\xEDce nese tvou moudrost dom\u016F. Dovol si zpomalit \u2014 \u017E\xE1dn\xFD sp\u011Bch, \u017E\xE1dn\xE9 n\xE1roky. Jen p\u0159\xEDtomnost. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED v reflexi a klidu"},{title:"Z\xE1m\u011Br",text:e=>`Zam\u011B\u0159 se na ${e.focus}. Zeptej se: "Co nov\xE9ho m\u011B tento cyklus nau\u010Dil? Jakou moudrost chci n\xE9st d\xE1l \u2014 a jakou sd\xEDlet s ostatn\xEDmi?" Setrvej v tichu, dokud nep\u0159ijde odpov\u011B\u010F.`,subtext:"Integrov\xE1n\xED moudrosti cyklu"},{title:"Vizualizace",text:e=>`Zav\u0159i o\u010Di. P\u0159edstav si ${e.vizObraz}. Pak si p\u0159edstav, jak tuto kvalitu \u2014 svou moudrost z cyklu \u2014 p\u0159ed\xE1v\xE1\u0161 jako dar n\u011Bkomu bl\xEDzk\xE9mu. Jak se tv\xE1\u0159\xED, kdy\u017E ji p\u0159ijme? A jak se c\xEDt\xED\u0161 ty?`,subtext:"Vizualizace sd\xEDlen\xED a p\u0159ed\xE1n\xED"},{title:"Fyzick\xFD \xFAkon",text:e=>"Napi\u0161 3 v\u011Bci, za kter\xE9 v tomto cyklu c\xEDt\xED\u0161 hlubokou vd\u011B\u010Dnost. Pak napi\u0161 1 konkr\xE9tn\xED moudrost nebo zku\u0161enost, kterou tento t\xFDden sd\xEDl\xED\u0161 s n\u011Bk\xFDm bl\xEDzk\xFDm. Konkr\xE9tn\u011B: s k\xFDm a co.",subtext:"Vd\u011B\u010Dnost stvrzen\xE1 a sd\xEDlen\xED napl\xE1novan\xE9"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakuj:

\u201EV ${e.mantraSlovo} a vd\u011B\u010Dnosti sd\xEDl\xEDm sv\u011Btlo, kter\xE9 ke mn\u011B p\u0159i\u0161lo.
M\xE1 moudrost roste p\u0159ed\xE1v\xE1n\xEDm \u2014 tak jako ${e.ruler} napl\u0148uje sv\u016Fj cyklus."`,subtext:"Opakuj t\u0159ikr\xE1t"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkuj za v\u0161e, co tento cyklus p\u0159inesl \u2014 dobr\xE9 i n\xE1ro\u010Dn\xE9. Oboj\xED bylo tv\xFDm u\u010Ditelem. ${e.uzavreniVeta} Zhasni sv\xED\u010Dku. Nese\u0161 moudrost d\xE1l \u2014 to je to nejvz\xE1cn\u011Bj\u0161\xED, co m\u016F\u017Ee\u0161 d\xE1t.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Jak\xE1 moudrost z tohoto cyklu m\u011B nejv\xEDce p\u0159ekvapila nebo zas\xE1hla?","Komu m\u016F\u017Eu p\u0159edat to, co m\u011B tento cyklus nau\u010Dil? Jak to ud\u011Bl\xE1m konkr\xE9tn\u011B?","Kde c\xEDt\xEDm nejhlub\u0161\xED vd\u011B\u010Dnost \u2014 i za to, co bylo t\u011B\u017Ek\xE9?",e.journalQ]},"last-quarter":{nazevPrefix:"Ritu\xE1l \u010Dist\u011Bn\xED",tema:"Posledn\xED \u010Dtvr\u0165 \u2014 propu\u0161t\u011Bn\xED a p\u0159\xEDprava prostoru",popis:e=>`M\u011Bs\xEDc se vrac\xED k temnot\u011B. Je \u010Das hlubok\xE9ho \xFAklidu \u2014 fyzick\xE9ho, emocion\xE1ln\xEDho i ment\xE1ln\xEDho. Tv\u016Fj \u017Eivel \u2014 ${e.element.toLowerCase()} \u2014 ti pom\xE1h\xE1 jasn\u011B vid\u011Bt, co n\xE9st d\xE1l a co v\u011Bdom\u011B pustit.`,prepList:["Sv\xED\u010Dka","Pap\xEDr a tu\u017Eka","Tich\xE9 m\xEDsto"],duration:"8\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsvi\u0165 sv\xED\u010Dku. T\u0159ikr\xE1t zhluboka d\xFDchej. S ka\u017Ed\xFDm v\xFDdechem si p\u0159edstav, jak vydechuje\u0161 v\u0161e star\xE9, p\u0159ebyte\u010Dn\xE9 a unavuj\xEDc\xED. C\xEDt\xED\u0161 se leh\u010D\xED s ka\u017Ed\xFDm dechem. Ub\xFDvaj\xEDc\xED M\u011Bs\xEDc nese star\xE9 pry\u010D. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED v o\u010Dist\u011B"},{title:"Z\xE1m\u011Br",text:e=>`Polo\u017E si ot\xE1zku: "Co v m\xE9m \u017Eivot\u011B zab\xEDr\xE1 m\xEDsto, ani\u017E by mi p\u0159in\xE1\u0161elo radost nebo smysl?" Nech ${e.focus}, a\u0165 ti pom\u016F\u017Ee rozli\u0161it, co je skute\u010Dn\u011B tvoje \u2014 a co si jen nese\u0161 ze zvyku nebo ze strachu.`,subtext:"Inventura p\u0159ebyte\u010Dn\xE9ho"},{title:"Vizualizace",text:e=>`Zav\u0159i o\u010Di. P\u0159edstav si ${e.vizObraz}. Pak si p\u0159edstav, jak p\u0159es tento obraz proch\xE1z\xED \u010Dist\xFD v\xEDtr. Odn\xE1\u0161\xED v\u0161e, co ti neslou\u017E\xED \u2014 bez dramatu, bez l\xEDtosti. Prostor po nich je sv\u011Btl\xFD, \u010Dist\xFD a p\u0159ipraven\xFD.`,subtext:"Vizualizace \u010Dist\xE9ho prostoru"},{title:"Fyzick\xFD \xFAkon",text:e=>'Napi\u0161 na pap\xEDr 3 v\u011Bci, kter\xE9 v\u011Bdom\u011B propou\u0161t\xED\u0161 \u2014 my\u0161lenky, n\xE1vyky, p\u0159edm\u011Bty nebo vztahy, kter\xE9 t\u011B u\u017E nevy\u017Eivuj\xED. Pro ka\u017Edou napi\u0161: "Propou\u0161t\xEDm _____, proto\u017Ee _____." Pak pap\xEDr p\u0159etrhni nebo vyho\u010F.',subtext:"V\u011Bdom\xE9 a konkr\xE9tn\xED propu\u0161t\u011Bn\xED"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakuj:

\u201EV ${e.mantraSlovo} a jasnosti \u010Dist\xEDm sv\u016Fj prostor.
To, co odch\xE1z\xED, vytv\xE1\u0159\xED m\xEDsto pro nov\xE9 \u2014 a ${e.ruler} mi d\xE1v\xE1 jasnost vid\u011Bt, co si n\xE9st d\xE1l."`,subtext:"Opakuj t\u0159ikr\xE1t"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkuj si za odvahu pustit to, co bylo t\u0159eba. Ka\u017Ed\xFD odchod je pozv\xE1nka pro p\u0159\xEDchod. ${e.uzavreniVeta} Zhasni sv\xED\u010Dku. Tv\u016Fj prostor \u2014 vnit\u0159n\xED i vn\u011Bj\u0161\xED \u2014 je \u010Dist\u0161\xED.`,subtext:"Ritu\xE1l dokon\u010Den"}],journalPrompts:e=>["Jak se c\xEDt\xEDm po tomto v\u011Bdom\xE9m propu\u0161t\u011Bn\xED? Co se pohnulo?","Co si s sebou do nov\xE9ho cyklu beru jako pou\u010Den\xED \u2014 ne jako b\u0159emeno?","Jak\xFD prostor se ve mn\u011B dnes otev\u0159el pro nov\xE9?",e.journalQ]},"waning-crescent":{nazevPrefix:"Ritu\xE1l ticha",tema:"Ub\xFDvaj\xEDc\xED srpek \u2014 obnova, odpo\u010Dinek a p\u0159\xEDprava",popis:e=>`M\u011Bs\xEDc t\xE9m\u011B\u0159 zmizel z oblohy. Cyklus se uzav\xEDr\xE1. Toto je nejintrovertovan\u011Bj\u0161\xED f\xE1ze \u2014 \u010Das skute\u010Dn\xE9ho odpo\u010Dinku, regenerace a tich\xE9 p\u0159\xEDpravy. Tv\u016Fj \u017Eivel \u2014 ${e.element.toLowerCase()} \u2014 si zaslou\u017E\xED klid.`,prepList:["Sv\xED\u010Dka","Pohodln\xE9 m\xEDsto k sezen\xED nebo lehnut\xED","Tich\xE1 m\xEDstnost bez ru\u0161iv\xFDch vliv\u016F"],duration:"7\u201310 minut",kroky:[{title:"Uzem\u011Bn\xED",text:e=>`Rozsvi\u0165 sv\xED\u010Dku. Lehni si nebo se pohodln\u011B posa\u010F. T\u0159ikr\xE1t zhluboka d\xFDchej bez jak\xE9hokoli z\xE1m\u011Bru \u2014 jen \u010Dist\xE9 d\xFDch\xE1n\xED. Dovol sv\xE9mu t\u011Blu a mysli odpo\u010D\xEDvat bez n\xE1roku na v\xFDkon. ${e.uzemeniVeta}`,subtext:"Uzem\u011Bn\xED v hlubok\xE9m klidu"},{title:"Z\xE1m\u011Br",text:e=>`Dne\u0161n\xED z\xE1m\u011Br je nejjednodu\u0161\u0161\xED ze v\u0161ech: dovolit si opravdu odpo\u010Dinout. Zeptej se ti\u0161e: "Co moje t\u011Blo a du\u0161e pot\u0159ebuj\xED k zotaven\xED a obnov\u011B?" Nech ${e.focus}, a\u0165 uk\xE1\u017Ee cestu k obnov\u011B.`,subtext:"Z\xE1m\u011Br v odpo\u010Dinku bez v\xFD\u010Ditek"},{title:"Vizualizace",text:e=>`Zav\u0159i o\u010Di. P\u0159edstav si ${e.vizObraz}. Tento obraz se pomalu rozpl\xFDv\xE1, jak M\u011Bs\xEDc ub\xFDv\xE1. Nech mysl spo\u010Dinout v tichu \u2014 \u017E\xE1dn\xE9 pl\xE1ny, \u017E\xE1dn\xE9 \xFAkoly, \u017E\xE1dn\xE1 anal\xFDza. Jen byt\xED v p\u0159\xEDtomn\xE9m okam\u017Eiku.`,subtext:"Vizualizace hlubok\xE9ho ticha"},{title:"Fyzick\xFD \xFAkon",text:e=>"Z\u016Fsta\u0148 3 minuty v absolutn\xEDm tichu. \u017D\xE1dn\xFD telefon, \u017E\xE1dn\xE1 hudba, \u017E\xE1dn\xE9 zpr\xE1vy. Jen ticho a sv\xED\u010Dka. Pokud p\u0159ijdou my\u0161lenky, p\u0159ijmi je laskav\u011B a nech je odej\xEDt jako mraky po obloze.",subtext:"3 minuty v\u011Bdom\xE9ho ticha"},{title:"Mantra",text:e=>`T\u0159ikr\xE1t opakuj \u2014 pomalu, t\xE9m\u011B\u0159 \u0161eptem:

\u201EV ${e.mantraSlovo} a tichu se obnovuji.
Nov\xFD cyklus za\u010D\xEDn\xE1 brzy \u2014 ${e.ruler} p\u0159ipravuje nov\xFD za\u010D\xE1tek."`,subtext:"\u0160eptej t\u0159ikr\xE1t \u2014 jemn\u011B"},{title:"Uzav\u0159en\xED",text:e=>`Pod\u011Bkuj si za tuto chv\xEDli zastaven\xED. Odpo\u010Dinek nen\xED slabost \u2014 je to p\u0159\xEDprava na v\u0161e, co p\u0159ijde. ${e.uzavreniVeta} Zhasni sv\xED\u010Dku. Novolun\u011Bn\xED se bl\xED\u017E\xED a s n\xEDm nov\xFD za\u010D\xE1tek.`,subtext:"Ritu\xE1l dokon\u010Den \u2014 cyklus se uzav\xEDr\xE1"}],journalPrompts:e=>["Jak se c\xEDt\xEDm, kdy\u017E si dovol\xEDm opravdu odpo\u010Dinout \u2014 bez v\xFD\u010Ditek?","Co z tohoto lun\xE1rn\xEDho cyklu si nesu jako dar a pou\u010Den\xED do nov\xE9ho?","Co by novolun\xED mohlo p\u0159in\xE9st, kdyby v\u0161e bylo mo\u017En\xE9?",e.journalQ]}};function u(e,s){const t=n[e]||n["full-moon"],o=a[s]||a.beran;return{nazev:`${t.nazevPrefix} \u2014 ${o.name}`,signName:o.name,signEmoji:o.emoji,signElement:o.element,signRuler:o.ruler,signBarva:o.barva,phaseSlug:e,signSlug:s,phaseTema:t.tema,popis:t.popis(o),prepList:t.prepList,duration:t.duration,kroky:t.kroky.map((i,l)=>({cislo:l+1,title:i.title,text:i.text(o),subtext:i.subtext})),journalPrompts:t.journalPrompts(o)}}function r(){return a}function v(){return Object.keys(n)}window.RitualContent={getRitual:u,getAllSigns:r,getAllPhases:v}})();})();
